import axios from 'axios';

const API_URL = process.env.NODE_ENV === 'production'
  ? 'https://your-render-backend-url.onrender.com' // <-- PASTE YOUR RENDER URL HERE
  : 'http://localhost:3001';

// NEW: Define the WebSocket URL
export const WEBSOCKET_URL = process.env.NODE_ENV === 'production'
  ? API_URL.replace(/^http/, 'ws') // Converts https:// to wss://
  : 'ws://localhost:3001';

const api = axios.create({
  baseURL: API_URL,
});

api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');
    if (token) {
      config.headers['Authorization'] = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

export default api;
